            </span>
          </div>
        </div>

        <div v-if="plan.id === 2" class="plan-extra">
          <div class="price-tag">
            <span class="price-label">体验价</span>
            <span class="price-value">¥{{ plan.price }}</span>
          </div>
          <div class="blindbox-preview">
            <div class="box-item" v-for="i in 4" :key="i">
